class Solution:
    def assignJobs(self, jobs: list[int], workers: int, resourceCapacity: int) -> bool:
	jobs.sort()
	currentWorker = 0
	currentCapacity = 0
	for difficulty in jobs:
		if currentCapacity + difficulty <= resourceCapacity:
			currentCapacity += difficulty
			currentWorker += 1
		if currentWorker >= workers:
			break
	return currentWorker

def main():
	jobs = [2, 3, 5, 1, 4]
	workers = 3
	resourceCapacity = 4
	print(Solution().assignJobs(jobs, workers, resourceCapacity))

