class Solution {
public:
bool assignJobs(vector<int>& jobs, int workers, int resourceCapacity) {
	sort(jobs.begin(), jobs.end());
	int currentWorker = 0;
	int currentCapacity = 0;
	for (int difficulty : jobs) {
		if (currentCapacity + difficulty <= resourceCapacity) {
			currentCapacity += difficulty;
			currentWorker++;
		}
		if (currentWorker >= workers) {
			break;
		}
	}
	return currentWorker;
}
};
